export type ComponentSVGParams = {
  tipo: string;
  ancho: number | null;
  alto: number | null;
  maxW?: number;
  maxH?: number;
};

const PALETTE = {
  frame: "#222",
  inner: "#444",
  glass: "rgba(185,220,240,0.22)",
  glassS: "rgba(100,170,210,0.55)",
  reflect1: "rgba(255,255,255,0.55)",
  reflect2: "rgba(255,255,255,0.30)",
  hw: "#333",
  dim: "#aaa",
  dimText: "#888",
  dash: "#555",
  label: "#999",
} as const;

const BASE_SIZES: Record<string, { w: number; h: number }> = {
  Ventana: { w: 160, h: 130 },
  Puerta: { w: 100, h: 160 },
  "Paño Fijo": { w: 140, h: 150 },
  "Shower door": { w: 95, h: 160 },
  "Cierre (Logia/Balcón)": { w: 200, h: 110 },
  Baranda: { w: 200, h: 80 },
  Espejo: { w: 110, h: 150 },
  "Tapa de mesa": { w: 180, h: 70 },
  Otro: { w: 130, h: 130 },
};

function escapeXml(value: string) {
  return value
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&apos;");
}

function clamp(value: number, min: number, max: number) {
  return Math.max(min, Math.min(value, max));
}

function formatMm(value: number | null) {
  return value ? `${Math.round(value)} mm` : "— mm";
}

function normalizeComponentType(tipo: string) {
  const normalized = tipo.trim().toLowerCase();

  if (normalized.startsWith("vent")) return "Ventana";
  if (normalized.startsWith("puert")) return "Puerta";
  if (normalized.includes("fijo")) return "Paño Fijo";
  if (normalized.startsWith("show")) return "Shower door";
  if (normalized.startsWith("cier")) return "Cierre (Logia/Balcón)";
  if (normalized.startsWith("bar")) return "Baranda";
  if (normalized.startsWith("esp")) return "Espejo";
  if (normalized.startsWith("tap")) return "Tapa de mesa";
  return "Otro";
}

function buildReflections(x: number, y: number, w: number, h: number) {
  return [
    `<line x1="${x + w * 0.18}" y1="${y + h * 0.14}" x2="${x + w * 0.38}" y2="${y + h * 0.32}" stroke="${PALETTE.reflect1}" stroke-width="2.2" stroke-linecap="round" />`,
    `<line x1="${x + w * 0.24}" y1="${y + h * 0.1}" x2="${x + w * 0.43}" y2="${y + h * 0.25}" stroke="${PALETTE.reflect2}" stroke-width="1.3" stroke-linecap="round" />`,
  ].join("");
}

function buildArrowHead(x: number, y: number, direction: "left" | "right" | "up" | "down") {
  if (direction === "left") {
    return `<path d="M${x + 6} ${y - 4} L${x} ${y} L${x + 6} ${y + 4}" fill="none" stroke="${PALETTE.dim}" stroke-width="1.1" stroke-linecap="round" stroke-linejoin="round" />`;
  }
  if (direction === "right") {
    return `<path d="M${x - 6} ${y - 4} L${x} ${y} L${x - 6} ${y + 4}" fill="none" stroke="${PALETTE.dim}" stroke-width="1.1" stroke-linecap="round" stroke-linejoin="round" />`;
  }
  if (direction === "up") {
    return `<path d="M${x - 4} ${y + 6} L${x} ${y} L${x + 4} ${y + 6}" fill="none" stroke="${PALETTE.dim}" stroke-width="1.1" stroke-linecap="round" stroke-linejoin="round" />`;
  }

  return `<path d="M${x - 4} ${y - 6} L${x} ${y} L${x + 4} ${y - 6}" fill="none" stroke="${PALETTE.dim}" stroke-width="1.1" stroke-linecap="round" stroke-linejoin="round" />`;
}

function buildHorizontalDimension(x: number, y: number, w: number, text: string) {
  return [
    `<line x1="${x}" y1="${y}" x2="${x + w}" y2="${y}" stroke="${PALETTE.dim}" stroke-width="1.1" />`,
    `<line x1="${x}" y1="${y - 7}" x2="${x}" y2="${y + 7}" stroke="${PALETTE.dim}" stroke-width="1" />`,
    `<line x1="${x + w}" y1="${y - 7}" x2="${x + w}" y2="${y + 7}" stroke="${PALETTE.dim}" stroke-width="1" />`,
    buildArrowHead(x, y, "left"),
    buildArrowHead(x + w, y, "right"),
    `<text x="${x + w / 2}" y="${y - 9}" text-anchor="middle" font-size="11" font-family="sans-serif" fill="${PALETTE.dimText}">${escapeXml(text)}</text>`,
  ].join("");
}

function buildVerticalDimension(x: number, y: number, h: number, text: string) {
  return [
    `<line x1="${x}" y1="${y}" x2="${x}" y2="${y + h}" stroke="${PALETTE.dim}" stroke-width="1.1" />`,
    `<line x1="${x - 7}" y1="${y}" x2="${x + 7}" y2="${y}" stroke="${PALETTE.dim}" stroke-width="1" />`,
    `<line x1="${x - 7}" y1="${y + h}" x2="${x + 7}" y2="${y + h}" stroke="${PALETTE.dim}" stroke-width="1" />`,
    buildArrowHead(x, y, "up"),
    buildArrowHead(x, y + h, "down"),
    `<text x="${x - 12}" y="${y + h / 2}" text-anchor="middle" font-size="11" font-family="sans-serif" fill="${PALETTE.dimText}" transform="rotate(-90 ${x - 12} ${y + h / 2})">${escapeXml(text)}</text>`,
  ].join("");
}

function buildSlidingArrow(x: number, y: number, w: number, reverse = false) {
  const startX = reverse ? x + w : x;
  const endX = reverse ? x : x + w;
  const midY = y;

  return [
    `<line x1="${startX}" y1="${midY}" x2="${endX}" y2="${midY}" stroke="${PALETTE.dash}" stroke-width="1.2" stroke-linecap="round" />`,
    buildArrowHead(startX, midY, reverse ? "right" : "left"),
    buildArrowHead(endX, midY, reverse ? "left" : "right"),
  ].join("");
}

function buildCommonFrame(params: {
  x: number;
  y: number;
  w: number;
  h: number;
  frameStroke: number;
  innerStroke: number;
}) {
  const inset = params.frameStroke * 0.75;

  return [
    `<rect x="${params.x}" y="${params.y}" width="${params.w}" height="${params.h}" rx="2" fill="none" stroke="${PALETTE.frame}" stroke-width="${params.frameStroke}" />`,
    `<rect x="${params.x + inset}" y="${params.y + inset}" width="${params.w - inset * 2}" height="${params.h - inset * 2}" rx="1.5" fill="${PALETTE.glass}" stroke="${PALETTE.glassS}" stroke-width="${params.innerStroke}" />`,
  ].join("");
}

function buildVentana(x: number, y: number, w: number, h: number, frameStroke: number, innerStroke: number) {
  const mid = x + w / 2;
  const handleY = y + h * 0.52;

  return [
    buildCommonFrame({ x, y, w, h, frameStroke, innerStroke }),
    buildReflections(x, y, w, h),
    `<line x1="${mid}" y1="${y + frameStroke * 0.8}" x2="${mid}" y2="${y + h - frameStroke * 0.8}" stroke="${PALETTE.inner}" stroke-width="${innerStroke * 2.1}" />`,
    `<line x1="${mid - 7}" y1="${handleY - 10}" x2="${mid - 7}" y2="${handleY + 10}" stroke="${PALETTE.hw}" stroke-width="${innerStroke * 1.4}" stroke-linecap="round" />`,
    `<line x1="${mid + 7}" y1="${handleY - 10}" x2="${mid + 7}" y2="${handleY + 10}" stroke="${PALETTE.hw}" stroke-width="${innerStroke * 1.4}" stroke-linecap="round" />`,
    `<line x1="${x + frameStroke * 0.8}" y1="${y + h - frameStroke * 1.1}" x2="${x + w - frameStroke * 0.8}" y2="${y + h - frameStroke * 1.1}" stroke="${PALETTE.inner}" stroke-width="${innerStroke}" opacity="0.45" />`,
    buildSlidingArrow(x + w * 0.14, y + h * 0.58, w * 0.22, false),
    buildSlidingArrow(x + w * 0.64, y + h * 0.58, w * 0.22, true),
  ].join("");
}

function buildPuerta(x: number, y: number, w: number, h: number, frameStroke: number, innerStroke: number) {
  const transomY = y + h * 0.6;
  const knobX = x + w - frameStroke * 1.8;
  const knobY = y + h * 0.56;

  return [
    buildCommonFrame({ x, y, w, h, frameStroke, innerStroke }),
    `<rect x="${x + frameStroke * 0.85}" y="${transomY}" width="${w - frameStroke * 1.7}" height="${h - (transomY - y) - frameStroke * 0.85}" fill="rgba(40,40,40,0.08)" stroke="none" />`,
    buildReflections(x, y, w, h * 0.62),
    `<line x1="${x + frameStroke * 0.7}" y1="${transomY}" x2="${x + w - frameStroke * 0.7}" y2="${transomY}" stroke="${PALETTE.inner}" stroke-width="${innerStroke * 1.9}" />`,
    `<rect x="${x - frameStroke * 0.55}" y="${y + h * 0.14}" width="${frameStroke * 0.9}" height="${h * 0.12}" rx="1.5" fill="${PALETTE.hw}" />`,
    `<rect x="${x - frameStroke * 0.55}" y="${y + h * 0.74}" width="${frameStroke * 0.9}" height="${h * 0.12}" rx="1.5" fill="${PALETTE.hw}" />`,
    `<circle cx="${knobX}" cy="${knobY}" r="${innerStroke * 1.8}" fill="${PALETTE.hw}" />`,
    `<line x1="${knobX - 7}" y1="${knobY}" x2="${knobX - 1}" y2="${knobY}" stroke="${PALETTE.hw}" stroke-width="${innerStroke * 1.1}" stroke-linecap="round" />`,
    `<path d="M${x + frameStroke * 0.5} ${y + h * 0.2} A${w * 0.56} ${h * 0.42} 0 0 0 ${x + w * 0.14} ${y + h * 0.9}" fill="none" stroke="${PALETTE.dash}" stroke-width="${innerStroke}" stroke-dasharray="5 4" />`,
  ].join("");
}

function buildPanoFijo(x: number, y: number, w: number, h: number, frameStroke: number, innerStroke: number) {
  const pillW = Math.max(40, w * 0.28);
  const pillH = Math.max(16, h * 0.11);
  const pillX = x + (w - pillW) / 2;
  const pillY = y + h / 2 - pillH / 2;

  return [
    buildCommonFrame({ x, y, w, h, frameStroke, innerStroke }),
    buildReflections(x, y, w, h),
    `<rect x="${pillX}" y="${pillY}" width="${pillW}" height="${pillH}" rx="${pillH / 2}" fill="rgba(255,255,255,0.72)" stroke="${PALETTE.label}" stroke-width="1" />`,
    `<text x="${x + w / 2}" y="${pillY + pillH * 0.68}" text-anchor="middle" font-size="${clamp(pillH * 0.5, 8, 12)}" font-family="sans-serif" fill="${PALETTE.label}" font-weight="700">FIJO</text>`,
  ].join("");
}

function buildShowerDoor(x: number, y: number, w: number, h: number, frameStroke: number, innerStroke: number) {
  return [
    `<line x1="${x + frameStroke * 0.4}" y1="${y}" x2="${x + w}" y2="${y}" stroke="${PALETTE.frame}" stroke-width="${frameStroke}" />`,
    `<line x1="${x + frameStroke * 0.4}" y1="${y + h}" x2="${x + w}" y2="${y + h}" stroke="${PALETTE.frame}" stroke-width="${frameStroke}" />`,
    `<line x1="${x + w}" y1="${y}" x2="${x + w}" y2="${y + h}" stroke="${PALETTE.frame}" stroke-width="${frameStroke}" />`,
    `<rect x="${x + frameStroke * 0.45}" y="${y + frameStroke * 0.55}" width="${w - frameStroke}" height="${h - frameStroke * 1.1}" fill="${PALETTE.glass}" stroke="${PALETTE.glassS}" stroke-width="${innerStroke}" />`,
    buildReflections(x + frameStroke * 0.4, y, w - frameStroke * 0.6, h),
    `<rect x="${x - frameStroke * 0.45}" y="${y + h * 0.2}" width="${frameStroke * 0.75}" height="${h * 0.13}" rx="1.5" fill="${PALETTE.hw}" />`,
    `<rect x="${x - frameStroke * 0.45}" y="${y + h * 0.67}" width="${frameStroke * 0.75}" height="${h * 0.13}" rx="1.5" fill="${PALETTE.hw}" />`,
    `<rect x="${x + w - frameStroke * 1.3}" y="${y + h * 0.34}" width="${innerStroke * 1.8}" height="${h * 0.3}" rx="2" fill="${PALETTE.hw}" />`,
    `<path d="M${x + frameStroke * 0.45} ${y + h * 0.2} A${w * 0.66} ${h * 0.38} 0 0 0 ${x + w * 0.12} ${y + h * 0.88}" fill="none" stroke="${PALETTE.dash}" stroke-width="${innerStroke}" stroke-dasharray="5 4" />`,
  ].join("");
}

function buildCierre(x: number, y: number, w: number, h: number, frameStroke: number, innerStroke: number) {
  const third = w / 3;
  const divider1 = x + third;
  const divider2 = x + third * 2;

  return [
    buildCommonFrame({ x, y, w, h, frameStroke, innerStroke }),
    buildReflections(x, y, w, h),
    `<line x1="${divider1}" y1="${y + frameStroke * 0.7}" x2="${divider1}" y2="${y + h - frameStroke * 0.7}" stroke="${PALETTE.inner}" stroke-width="${innerStroke * 1.8}" />`,
    `<line x1="${divider2}" y1="${y + frameStroke * 0.7}" x2="${divider2}" y2="${y + h - frameStroke * 0.7}" stroke="${PALETTE.inner}" stroke-width="${innerStroke * 1.8}" />`,
    `<line x1="${x + frameStroke * 0.8}" y1="${y + h - frameStroke * 1.1}" x2="${x + w - frameStroke * 0.8}" y2="${y + h - frameStroke * 1.1}" stroke="${PALETTE.inner}" stroke-width="${innerStroke}" opacity="0.45" />`,
    `<line x1="${divider1 - 5}" y1="${y + h * 0.5 - 9}" x2="${divider1 - 5}" y2="${y + h * 0.5 + 9}" stroke="${PALETTE.hw}" stroke-width="${innerStroke * 1.3}" stroke-linecap="round" />`,
    `<line x1="${divider1 + 5}" y1="${y + h * 0.5 - 9}" x2="${divider1 + 5}" y2="${y + h * 0.5 + 9}" stroke="${PALETTE.hw}" stroke-width="${innerStroke * 1.3}" stroke-linecap="round" />`,
    `<line x1="${divider2 - 5}" y1="${y + h * 0.5 - 9}" x2="${divider2 - 5}" y2="${y + h * 0.5 + 9}" stroke="${PALETTE.hw}" stroke-width="${innerStroke * 1.3}" stroke-linecap="round" />`,
    `<line x1="${divider2 + 5}" y1="${y + h * 0.5 - 9}" x2="${divider2 + 5}" y2="${y + h * 0.5 + 9}" stroke="${PALETTE.hw}" stroke-width="${innerStroke * 1.3}" stroke-linecap="round" />`,
    buildSlidingArrow(x + third * 0.2, y + h * 0.57, third * 0.44, false),
    buildSlidingArrow(x + third * 2.34, y + h * 0.57, third * 0.44, true),
  ].join("");
}

function buildBaranda(x: number, y: number, w: number, h: number, frameStroke: number, innerStroke: number) {
  const railH = Math.max(7, h * 0.11);
  const glassY = y + railH;
  const glassH = h - railH * 2;
  const innerGap = w / 6;

  return [
    `<rect x="${x}" y="${y}" width="${w}" height="${railH}" fill="${PALETTE.frame}" />`,
    `<rect x="${x}" y="${y + h - railH}" width="${w}" height="${railH}" fill="${PALETTE.frame}" />`,
    `<rect x="${x}" y="${y}" width="${frameStroke * 1.4}" height="${h}" fill="${PALETTE.inner}" />`,
    `<rect x="${x + w - frameStroke * 1.4}" y="${y}" width="${frameStroke * 1.4}" height="${h}" fill="${PALETTE.inner}" />`,
    `<rect x="${x + frameStroke * 1.4}" y="${glassY}" width="${w - frameStroke * 2.8}" height="${glassH}" fill="${PALETTE.glass}" stroke="${PALETTE.glassS}" stroke-width="${innerStroke}" />`,
    buildReflections(x + frameStroke * 1.5, glassY, w - frameStroke * 3, glassH),
    Array.from({ length: 5 }, (_, index) => {
      const px = x + innerGap * (index + 1);
      return `<line x1="${px}" y1="${glassY + 3}" x2="${px}" y2="${glassY + glassH - 3}" stroke="${PALETTE.inner}" stroke-width="${innerStroke * 1.1}" opacity="0.42" />`;
    }).join(""),
  ].join("");
}

function buildEspejo(x: number, y: number, w: number, h: number, frameStroke: number, innerStroke: number) {
  const innerInset = frameStroke * 1.5;

  return [
    `<rect x="${x}" y="${y}" width="${w}" height="${h}" rx="2" fill="rgba(215,228,236,0.46)" stroke="${PALETTE.frame}" stroke-width="${frameStroke}" />`,
    `<rect x="${x + innerInset}" y="${y + innerInset}" width="${w - innerInset * 2}" height="${h - innerInset * 2}" rx="1.5" fill="rgba(205,220,230,0.52)" stroke="${PALETTE.inner}" stroke-width="${innerStroke}" />`,
    `<path d="M${x + w * 0.18} ${y + h * 0.12} L${x + w * 0.64} ${y + h * 0.54} L${x + w * 0.52} ${y + h * 0.68} L${x + w * 0.1} ${y + h * 0.24} Z" fill="rgba(255,255,255,0.28)" />`,
    buildReflections(x, y, w, h),
  ].join("");
}

function buildMesa(x: number, y: number, w: number, h: number, innerStroke: number) {
  const offsetX = w * 0.18;
  const offsetY = h * 0.28;
  const thickness = Math.max(10, h * 0.16);
  const top = [
    [x + offsetX, y],
    [x + w, y],
    [x + w - offsetX, y + offsetY],
    [x, y + offsetY],
  ];
  const front = [
    [x, y + offsetY],
    [x + w - offsetX, y + offsetY],
    [x + w - offsetX, y + offsetY + thickness],
    [x, y + offsetY + thickness],
  ];
  const side = [
    [x + w - offsetX, y + offsetY],
    [x + w, y],
    [x + w, y + thickness],
    [x + w - offsetX, y + offsetY + thickness],
  ];

  const points = (values: number[][]) => values.map(([px, py]) => `${px},${py}`).join(" ");

  return [
    `<polygon points="${points(top)}" fill="${PALETTE.glass}" stroke="${PALETTE.frame}" stroke-width="${innerStroke * 1.7}" />`,
    `<polygon points="${points(front)}" fill="rgba(34,34,34,0.08)" stroke="${PALETTE.inner}" stroke-width="${innerStroke}" />`,
    `<polygon points="${points(side)}" fill="rgba(34,34,34,0.12)" stroke="${PALETTE.inner}" stroke-width="${innerStroke}" />`,
    `<line x1="${x + offsetX}" y1="${y + 2}" x2="${x + w - offsetX * 0.45}" y2="${y + 2}" stroke="${PALETTE.reflect1}" stroke-width="2" stroke-linecap="round" />`,
  ].join("");
}

function buildOtro(x: number, y: number, w: number, h: number, frameStroke: number, innerStroke: number) {
  return [
    `<rect x="${x}" y="${y}" width="${w}" height="${h}" rx="2" fill="${PALETTE.glass}" stroke="${PALETTE.frame}" stroke-width="${frameStroke}" stroke-dasharray="7 6" />`,
    buildReflections(x, y, w, h),
    `<line x1="${x + w / 2}" y1="${y + h * 0.34}" x2="${x + w / 2}" y2="${y + h * 0.56}" stroke="${PALETTE.hw}" stroke-width="${innerStroke * 1.7}" stroke-linecap="round" />`,
    `<line x1="${x + w * 0.39}" y1="${y + h * 0.45}" x2="${x + w * 0.61}" y2="${y + h * 0.45}" stroke="${PALETTE.hw}" stroke-width="${innerStroke * 1.7}" stroke-linecap="round" />`,
    `<text x="${x + w / 2}" y="${y + h * 0.72}" text-anchor="middle" font-size="11" font-family="sans-serif" fill="${PALETTE.label}">OTRO / componente personalizado</text>`,
  ].join("");
}

function buildTypeLabel(type: string) {
  switch (type) {
    case "Ventana":
      return "Ventana corredera · 2 hojas";
    case "Puerta":
      return "Puerta batiente · 1 hoja";
    case "Paño Fijo":
      return "Paño fijo · vidrio continuo";
    case "Shower door":
      return "Shower door · batiente frameless";
    case "Cierre (Logia/Balcón)":
      return "Cierre logia/balcón · 3 hojas";
    case "Baranda":
      return "Baranda de vidrio";
    case "Espejo":
      return "Espejo decorativo";
    case "Tapa de mesa":
      return "Tapa de mesa · vista isométrica";
    default:
      return "Componente personalizado";
  }
}

export function generateComponentSVG(params: ComponentSVGParams): string {
  const resolvedType = normalizeComponentType(params.tipo);
  const fallbackBase = BASE_SIZES[resolvedType] ?? BASE_SIZES.Otro;
  const ratioW = params.ancho && params.alto ? params.ancho : fallbackBase.w;
  const ratioH = params.ancho && params.alto ? params.alto : fallbackBase.h;
  const maxW = params.maxW ?? 200;
  const maxH = params.maxH ?? 180;
  const scaleW = maxW / ratioW;
  const scaleH = maxH / ratioH;
  const scale = Math.min(scaleW, scaleH, 1.8);
  const drawW = Math.max(68, Math.round(ratioW * scale));
  const drawH = Math.max(52, Math.round(ratioH * scale));
  const dimLeft = resolvedType === "Tapa de mesa" ? 40 : 46;
  const dimBottom = 42;
  const topPad = 12;
  const rightPad = 12;
  const totalW = drawW + dimLeft + rightPad;
  const totalH = drawH + topPad + dimBottom;
  const originX = dimLeft;
  const originY = topPad;
  const frameStroke = clamp(Math.min(drawW, drawH) * 0.07, 4, 10);
  const innerStroke = clamp(frameStroke * 0.34, 1.1, 2.6);
  const label = buildTypeLabel(resolvedType);

  let drawing = "";

  switch (resolvedType) {
    case "Ventana":
      drawing = buildVentana(originX, originY, drawW, drawH, frameStroke, innerStroke);
      break;
    case "Puerta":
      drawing = buildPuerta(originX, originY, drawW, drawH, frameStroke, innerStroke);
      break;
    case "Paño Fijo":
      drawing = buildPanoFijo(originX, originY, drawW, drawH, frameStroke, innerStroke);
      break;
    case "Shower door":
      drawing = buildShowerDoor(originX, originY, drawW, drawH, frameStroke, innerStroke);
      break;
    case "Cierre (Logia/Balcón)":
      drawing = buildCierre(originX, originY, drawW, drawH, frameStroke, innerStroke);
      break;
    case "Baranda":
      drawing = buildBaranda(originX, originY, drawW, drawH, frameStroke, innerStroke);
      break;
    case "Espejo":
      drawing = buildEspejo(originX, originY, drawW, drawH, frameStroke, innerStroke);
      break;
    case "Tapa de mesa":
      drawing = buildMesa(originX, originY + drawH * 0.1, drawW, drawH * 0.72, innerStroke);
      break;
    default:
      drawing = buildOtro(originX, originY, drawW, drawH, frameStroke, innerStroke);
      break;
  }

  const dimensions =
    resolvedType === "Tapa de mesa"
      ? buildVerticalDimension(
          originX - 22,
          originY + drawH * 0.28,
          Math.max(14, drawH * 0.16),
          formatMm(params.alto ?? 10)
        )
      : [
          buildHorizontalDimension(originX, originY + drawH + 18, drawW, formatMm(params.ancho)),
          buildVerticalDimension(originX - 20, originY, drawH, formatMm(params.alto)),
        ].join("");

  return [
    `<svg xmlns="http://www.w3.org/2000/svg" width="${totalW}" height="${totalH}" viewBox="0 0 ${totalW} ${totalH}" aria-hidden="true" role="img">`,
    `<g>`,
    drawing,
    dimensions,
    `<text x="${originX + drawW / 2}" y="${totalH - 8}" text-anchor="middle" font-size="11" font-family="sans-serif" fill="${PALETTE.label}" font-weight="600">${escapeXml(label)}</text>`,
    `</g>`,
    `</svg>`,
  ].join("");
}
